import{_ as a,o as i,c as e,a2 as n}from"./chunks/framework.D5wUhsuj.js";const c=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"guide/quick-start.md","filePath":"guide/quick-start.md"}'),t={name:"guide/quick-start.md"};function l(r,s,p,h,d,o){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>This guide takes a fresh VPS to a working AidiPanel installation and an isolated first site.</p><h2 id="_1-prepare-the-server" tabindex="-1">1. Prepare the server <a class="header-anchor" href="#_1-prepare-the-server" aria-label="Permalink to &quot;1. Prepare the server&quot;">​</a></h2><p>Use a fresh Ubuntu 22.04/24.04 or Debian 11/12 VPS with root or sudo access. Update it before installing AidiPanel:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>If the upgrade requests a reboot, complete it before continuing:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-f</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /var/run/reboot-required ]; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reboot</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Reconnect over SSH after the server comes back online.</p><h2 id="_2-install-aidipanel" tabindex="-1">2. Install AidiPanel <a class="header-anchor" href="#_2-install-aidipanel" aria-label="Permalink to &quot;2. Install AidiPanel&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://get.aidipanel.com</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The URL redirects to the installer from the latest stable GitHub release. Save the generated panel password printed at the end. It is also stored in <code>/opt/aidipanel/credentials.conf</code>, readable only by root.</p><p>For checksum verification and installer options, see <a href="/docs/guide/installation">Installation</a>.</p><h2 id="_3-sign-in" tabindex="-1">3. Sign in <a class="header-anchor" href="#_3-sign-in" aria-label="Permalink to &quot;3. Sign in&quot;">​</a></h2><p>Open <code>https://&lt;server-ip&gt;:8443</code> and sign in as <code>admin</code> with the generated password.</p><div class="warning custom-block"><p class="custom-block-title">Initial certificate warning</p><p>The panel initially uses a self-signed certificate. Verify that you are connecting to the intended server before accepting the browser warning. You can assign a domain and trusted certificate from panel settings later.</p></div><h2 id="_4-point-dns-to-the-server" tabindex="-1">4. Point DNS to the server <a class="header-anchor" href="#_4-point-dns-to-the-server" aria-label="Permalink to &quot;4. Point DNS to the server&quot;">​</a></h2><p>Create an <code>A</code> record for your domain using the server&#39;s public IPv4 address. Add an <code>AAAA</code> record only when IPv6 is configured correctly.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +short</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Wait until the result matches your server before requesting a trusted certificate.</p><h2 id="_5-create-a-site" tabindex="-1">5. Create a site <a class="header-anchor" href="#_5-create-a-site" aria-label="Permalink to &quot;5. Create a site&quot;">​</a></h2><p>For a generic PHP site:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> site:add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This creates <code>/home/example/htdocs/example.com</code>, a dedicated no-login Linux user, an isolated PHP-FPM pool, and an Nginx vhost. You can also create the site from <strong>Sites → Add Site</strong> in the panel.</p><h3 id="wordpress" tabindex="-1">WordPress <a class="header-anchor" href="#wordpress" aria-label="Permalink to &quot;WordPress&quot;">​</a></h3><p>WordPress provisioning requires the site title and administrator details. Pass the password over stdin so it is not retained in shell history:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;%s\\n&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;StrongPassword123!&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> site:add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blog.example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blog</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wordpress</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --wp-title</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Example Blog&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --wp-admin-user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --wp-admin-pass-stdin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --wp-admin-email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin@example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>The command installs WordPress, creates its database and database user, writes <code>wp-config.php</code>, and creates the administrator account as one workflow. The panel form provides the same required fields.</p><h2 id="_6-install-ssl" tabindex="-1">6. Install SSL <a class="header-anchor" href="#_6-install-ssl" aria-label="Permalink to &quot;6. Install SSL&quot;">​</a></h2><p>After DNS resolves to the server:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ssl:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin@example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>New sites allow HTTP initially and use a temporary self-signed certificate for HTTPS. After a trusted certificate is active, enable force HTTPS and HSTS from the site&#39;s SSL tab when appropriate.</p><h2 id="_7-enable-caching-when-appropriate" tabindex="-1">7. Enable caching when appropriate <a class="header-anchor" href="#_7-enable-caching-when-appropriate" aria-label="Permalink to &quot;7. Enable caching when appropriate&quot;">​</a></h2><p>Page cache is off by default:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>For WordPress, enable the Nginx cache helper from the panel or use the documented CLI option so publishing content can purge stale pages. Review <a href="/docs/guide/fastcgi-cache">FastCGI Cache</a> before enabling it on dynamic applications.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><div class="ap-cards"><p><strong><a href="/docs/guide/sites">Site Management →</a></strong> Learn site types, file paths, PHP selection, security, backups, and deletion behavior.</p><p><strong><a href="/docs/reference/cli">CLI Reference →</a></strong> Browse all supported command groups and safe examples.</p><p><strong><a href="/docs/troubleshooting/">Troubleshooting →</a></strong> Start with symptoms when an installation, domain, certificate, or site is not working.</p></div>`,37)])])}const g=a(t,[["render",l]]);export{c as __pageData,g as default};
